import avatar from '@/components/shared/avatar/avatar';
import { ComponentModule, render } from '@/main';
import { Empresa } from '@/models/empresa';
import { User } from '@/models/user';
import { getCompanyGlobalData } from '@/services/api.service';
import { getAuthenticatedUser, logout } from '@/services/auth.service';
import { Dropdown } from 'flowbite';

export default {
    name: () => 'nav',
    template: () => import('./nav.html?raw'),
    data: () => ({
        loading: false,
        avatar: null as string | null,
        user: null as User | null,
        empresa: null as Empresa | null,
        async init() {
            console.log('nav@init');

            try {
                this.user = await getAuthenticatedUser();
                this.empresa = await getCompanyGlobalData(this.user.empOmi);
            } catch (error) {
                location.href = '/login';
            }

            this.avatar = await render(avatar);

            this.configureUserDropdown();
        },
        async logout() {
            console.log('nav@logout');
            this.loading = true;

            try {
                await logout();
                this.$router.navigate('/login');
            } catch (error: any) {
                console.error('Error logging out', error);
            }

            this.loading = false;
        },
        configureUserDropdown() {
            new Dropdown(this.$refs.dropdown, this.$refs.dropdownTrigger, {
                placement: 'bottom',
                triggerType: 'click',
                offsetSkidding: 0,
                offsetDistance: 10,
                delay: 300,
                ignoreClickOutsideClass: false,
                onHide: () => {
                    console.log('dropdown has been hidden');
                },
                onShow: () => {
                    console.log('dropdown has been shown');
                },
                onToggle: () => {
                    console.log('dropdown has been toggled');
                },
            });
        },
    }),
} as ComponentModule;
