import { ComponentModule } from '@/main';
import { Empresa } from '@/models/empresa';
import { DRAWER_TOGGLE } from '@/models/events';
import { Item } from '@/models/menu';
import { User } from '@/models/user';
import { getCompanyGlobalData } from '@/services/api.service';
import { getAuthenticatedUser } from '@/services/auth.service';
import { getMenuItems } from '@/services/menu.service';
import { Drawer } from 'flowbite';

const breakPoint = 1024;

export default {
    name: () => 'aside',
    template: () => import('./aside.html?raw'),
    data: () => ({
        loading: false,
        user: null as User | null,
        empresa: null as Empresa | null,
        drawer: null as Drawer | null,
        menu: [] as Item[],
        async init() {
            console.log('aside@init');

            try {
                this.user = await getAuthenticatedUser();
                this.empresa = await getCompanyGlobalData(this.user.empOmi);
                this.menu = await getMenuItems();
            } catch (error) {
                location.href = '/login';
            }

            this.drawer = new Drawer(this.$refs.drawerNavigation, {
                placement: 'left',
                backdrop: false,
                // backdropClasses: 'bg-gray-900/50 dark:bg-gray-900/80 fixed inset-0 z-30',
                bodyScrolling: true,
                edge: false,
                edgeOffset: '',
                onHide: () => {
                    console.log('drawer is hidden');
                },
                onShow: () => {
                    console.log('drawer is shown');
                },
                onToggle: () => {
                    console.log('drawer has been toggled');
                },
            });

            this.$nextTick(() => {
                if (window.innerWidth >= breakPoint) {
                    this.drawer?.show();
                }

                console.log('aside drawer visible status', this.drawer?.isVisible());

                window.onresize = () => {
                    if (window.innerWidth >= breakPoint) {
                        this.drawer?.show();
                    }

                    if (window.innerWidth < breakPoint) {
                        this.drawer?.hide();
                    }
                };

                // @ts-expect-error 2769
                window.addEventListener(DRAWER_TOGGLE, (e: CustomEvent) => {
                    if (e.detail === 'drawerNavigation') {
                        this.drawer?.toggle();
                    }
                });
            });
        },
    }),
} as ComponentModule;
