import { ComponentModule } from '@/main';
import { User } from '@/models/user';
import { url } from '@/services/api.service';
import { getAuthenticatedUser } from '@/services/auth.service';

export default {
    name: () => 'avatar',
    template: () => import('./avatar.html?raw'),
    data: () => ({
        loading: false,
        user: null as User | null,
        img: 'https://ui-avatars.com/api/?size=1&color=fff&background=fff',
        async init() {
            console.log('avatar@init');

            try {
                this.user = await getAuthenticatedUser();
            } catch (error) {
                return;
            }

            const cacheKey = '_avatarUrl';

            if (window.cache.has(cacheKey)) {
                this.img = window.cache.get(cacheKey);
                return;
            }

            const imageUrl = url(`/isiWeb/web/v1/profile-image?user=${this.user.usuario}`);
            const defaultImageUrl = `https://ui-avatars.com/api/?size=48&color=ed772d&background=ffffff&name=${this.user.nombre}`;

            try {
                const r = await fetch(imageUrl, {
                    credentials: 'include',
                });

                this.img = r.ok ? imageUrl : defaultImageUrl;
                window.cache.set(cacheKey, this.img);
            } catch (error: any) {
                this.img = defaultImageUrl;
                window.cache.set(cacheKey, this.img);
            }
        },
    }),
} as ComponentModule;
